def show_inventory(items):
    print('Инвентарь:')
    for i, item in enumerate(items, 1):
        print(f'{i}. {item}')

def find_artifact(items, artifact_name):
    return artifact_name in items

def calc_total_weight(items, weight_dict):
    total = 0
    for item in items:
        if item in weight_dict:
            total += weight_dict[item]
    return total

name = input('Имя героя: ')

inventory = []
print('Собирай инвентарь. Введи "стоп" для завершения.')

while True:
    item = input('Предмет: ')
    if item == 'стоп':
        break
    inventory.append(item)

print(f'\n--- Отчёт героя {name} ---')
show_inventory(inventory)

if len(inventory) > 0:
    choice = int(input('\nКакой предмет использовать? (номер): '))
    print(f'Использован: {inventory[choice - 1]}')

artifact = 'Кристалл мудрости'
if find_artifact(inventory, artifact):
    print(f'✨ Ты нашёл {artifact}!')
else:
    print(f'{artifact} не найден.')

weights = {'меч': 3, 'щит': 5, 'зелье': 1, 'шлем': 2, 'кольцо': 1, 'амулет': 2, 'кристалл': 1}
total_weight = calc_total_weight(inventory, weights)

print(f'\nИтог:')
print(f'Герой: {name}')
print(f'Предметов: {len(inventory)}')
print(f'Общий вес: {total_weight} кг')

if total_weight > 10:
    print('⚖ Слишком тяжело! Герой еле двигается.')
else:
    print('✅ Вес в норме. В путь!')
